#include<bits/stdc++.h>
using namespace std;
int main() {
	int a[129][7], n, n2 = 1, b[8];
	cin >> n;
	for (int i = 0; i < n; i++) {
		n2 *= 2;
		b[i] = n2;
	}
	for (int i = 0; i < n2; i++) {
		cin >> a[i][0];
	}
	for (int i = 0; i < n; i++) {

		for (int j = 0; j < b[n - i - 1]; j += 2) {
			if (a[j][i] > a[j + 1][i]) {
				a[j / 2][i + 1] = a[j][i];
			} else {
				a[j / 2][i + 1] = a[j + 1][i];
			}
		}
	}
	if (a[1][n - 1] < a[0][n - 1]) {
		for (int i = 0; i < n2; i++) {
			if (a[i][0] == a[1][n - 1]) {
				cout << i+1;
			}
		}
	} else {
		for (int i = 0; i < n2; i++) {
			if (a[i][0] == a[0][n - 1]) {
				cout << i+1;
			}
		}
	}
	return 0;
}
